+        TestHarness::new("shadow_mode_vs_enforced_mode_telemetry_comparison_shadow");
+    let config_shadow = RuntimeRiskConfig {
+        enabled: true,
+        enforce: false,
+        alpha: 0.01,
+        window_size: 64,
