+        policy: &policy_s,
+        js_runtime: None,
+        interceptor: None,
+    };
+
+    futures::executor::block_on(async {
+        for idx in 0..10 {
+            let call_enforced = HostCallPayload {
+                call_id: format!("cmp-{idx}"),
